import time, random

def retry_with_backoff(fn, max_retries=4, base_delay=1.0):
    for attempt in range(max_retries):
        try:
            return fn()
        except (RateLimitError, ServiceUnavailableError) as e:
            if attempt == max_retries - 1:
                raise
            delay = base_delay * (2 ** attempt)  # 1s, 2s, 4s, 8s
            jitter = random.uniform(0, delay * 0.1)  # variacion aleatoria
            time.sleep(delay + jitter)

def run_kyc_check(applicant_id: str) -> dict:
    try:
        result = kyc_provider.verify(applicant_id)
        return {"status": "success", "verification_id": result.id}
    except ProviderTimeout:
        return {
            "error_code": "SERVICE_UNAVAILABLE",
            "retry_after_seconds": 30,
            "suggested_action": "retry",
        }
    except InvalidApplicantError:
        return {
            "error_code": "INVALID_INPUT",
            "suggested_action": "escalate_to_human",
            "message": "Applicant data failed validation",
        }

